import re,math
from pathlib import Path
p=Path('image.ppm')
s=p.read_bytes()
lines=s.split(b'\n')
w,h=map(int,lines[1].split())
vals=list(map(int,re.findall(rb'\d+',b'\n'.join(lines[3:]))))

def pix(x,y):
    i=(y*w+x)*3
    return tuple(vals[i:i+3])
# Fit R as a + b*cos(2*pi*x/T) + c*y + d
import numpy as np
xs=np.arange(w)
ys=[0,100,200,300,400,500]
for y in ys:
    R=np.array([pix(x,y)[0] for x in xs])
    # try least squares with components: const, cos(2*pi*x/T) for T in [50,80,100,160,200,400,800]
    best=None
    for T in [50,80,100,160,200,400,800]:
        C=np.cos(2*math.pi*xs/T)
        A=np.vstack([np.ones_like(xs),C]).T
        coef=np.linalg.lstsq(A,R,rcond=None)[0]
        pred=A.dot(coef)
        err=np.max(np.abs(pred-R))
        best=(T,coef,err) if best is None or err<best[2] else best
    print('y',y,'best cos fit',best)
# Check radial symmetry around center for grayscale
cx,cy=w/2,h/2
